"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import {
  getRandomComplete,
  getRandomEncourage,
  triggerShake,
} from "@/lib/learningMessages";
import { playClick, playCelebrate } from "@/lib/sounds";

const GRID_COLS = 8;
const GRID_ROWS = 6;
const CELL_SIZE = 40;

interface Combo {
  l: number;
  w: number;
  label: string;
}

const EX1_COMBOS: Combo[] = [
  { l: 7, w: 1, label: "长7、宽1" },
  { l: 6, w: 2, label: "长6、宽2" },
  { l: 5, w: 3, label: "长5、宽3" },
  { l: 4, w: 4, label: "长4、宽4（正方形）" },
];

const EX2_COMBOS: Combo[] = [
  { l: 5, w: 1, label: "长5、宽1" },
  { l: 4, w: 2, label: "长4、宽2" },
  { l: 3, w: 3, label: "长3、宽3（正方形）" },
];

export default function DrawPage() {
  const [exercise, setExercise] = useState<1 | 2 | "done">(1);
  const [ex1Selected, setEx1Selected] = useState<Set<string>>(new Set());
  const [ex2Selected, setEx2Selected] = useState<Set<string>>(new Set());
  const [highlight, setHighlight] = useState<{ l: number; w: number } | null>(
    null
  );
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);
  const [encourageMsg, setEncourageMsg] = useState("");
  const gridRef = useRef<HTMLDivElement>(null);

  const handleSelect = useCallback(
    (combo: Combo, ex: 1 | 2) => {
      const key = `${combo.l}-${combo.w}`;
      const selectedSet = ex === 1 ? ex1Selected : ex2Selected;

      if (selectedSet.has(key)) {
        setEncourageMsg(getRandomEncourage());
        triggerShake(gridRef.current);
        setTimeout(() => setEncourageMsg(""), 1500);
        setHighlight({ l: combo.l, w: combo.w });
        return;
      }

      setHighlight({ l: combo.l, w: combo.w });
      playClick();

      if (ex === 1) {
        setEx1Selected((prev) => {
          const next = new Set(prev);
          next.add(key);
          return next;
        });
      } else {
        setEx2Selected((prev) => {
          const next = new Set(prev);
          next.add(key);
          return next;
        });
      }
    },
    [ex1Selected, ex2Selected]
  );

  useEffect(() => {
    if (exercise === 2 && ex2Selected.size >= 2) {
      const t = setTimeout(() => {
        setExercise("done");
        playCelebrate();
      }, 800);
      return () => clearTimeout(t);
    }
  }, [ex2Selected, exercise]);

  const nextStep = getNextStep("perimeter", "draw");

  const currentCombos = exercise === 1 ? EX1_COMBOS : EX2_COMBOS;
  const currentSelected = exercise === 1 ? ex1Selected : ex2Selected;
  const perimeter = exercise === 1 ? 16 : 12;
  const halfPerimeter = exercise === 1 ? 8 : 6;

  return (
    <StepShell topicId="perimeter" stepId="draw">
      {/* 情境说明 */}
      <div className="mb-6 rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-soft)] p-4 text-center">
        <p className="font-medium text-[var(--text)]">
          练习 {exercise === "done" ? "完成" : exercise}：在方格纸上画出周长 ={" "}
          {perimeter}cm 的长方形
        </p>
        <p className="mt-1 text-sm text-[var(--text-secondary)]">
          提示：长 + 宽 = {halfPerimeter}cm
        </p>
      </div>

      {/* 方格纸 */}
      <div className="mb-6 rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
        <div className="flex justify-center">
          <div
            ref={gridRef}
            className="grid gap-0.5"
            style={{
              gridTemplateColumns: `repeat(${GRID_COLS}, ${CELL_SIZE}px)`,
            }}
          >
            {Array.from({ length: GRID_ROWS }).map((_, r) =>
              Array.from({ length: GRID_COLS }).map((_, c) => {
                const isHighlighted =
                  highlight !== null && r < highlight.w && c < highlight.l;
                return (
                  <div
                    key={`${r}-${c}`}
                    className="rounded-sm transition-all duration-300"
                    style={{
                      width: CELL_SIZE,
                      height: CELL_SIZE,
                      border: "1px dashed var(--signal-pending)",
                      backgroundColor: isHighlighted
                        ? "var(--primary)"
                        : "transparent",
                      opacity: isHighlighted ? 0.5 : 0.25,
                    }}
                  />
                );
              })
            )}
          </div>
        </div>
        <p className="mt-3 text-center text-xs text-[var(--text-muted)]">
          每个格子 = 1cm × 1cm
        </p>
        {encourageMsg && (
          <p className="mt-2 animate-float-in text-center text-sm text-[var(--accent)]">
            {encourageMsg}
          </p>
        )}
      </div>

      {exercise !== "done" ? (
        <div className="space-y-6">
          {/* 组合选择 */}
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <p className="mb-4 text-center text-sm text-[var(--text-secondary)]">
              点击按钮，看看不同长宽组合画出的长方形
            </p>
            <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
              {currentCombos.map((combo) => {
                const key = `${combo.l}-${combo.w}`;
                const isSelected = currentSelected.has(key);
                return (
                  <button
                    key={key}
                    onClick={() => handleSelect(combo, exercise)}
                    className={`relative rounded-lg border px-3 py-3 text-sm font-medium transition-all hover:scale-105 ${
                      isSelected
                        ? "border-[var(--primary)] bg-[var(--primary)]/10 text-[var(--primary)]"
                        : "border-[var(--border)] bg-[var(--bg-soft)] text-[var(--text)] hover:border-[var(--primary-light)]"
                    }`}
                  >
                    {combo.label}
                    {isSelected && (
                      <span className="absolute -top-1 -right-1 flex h-5 w-5 items-center justify-center rounded-full bg-[var(--signal-success)] text-[10px] text-white">
                        ✓
                      </span>
                    )}
                  </button>
                );
              })}
            </div>

            {/* 练习1揭示 */}
            {exercise === 1 && ex1Selected.size >= 2 && (
              <div className="mt-6 animate-float-in text-center">
                <p className="text-lg font-semibold text-[var(--signal-success)]">
                  周长16cm的长方形有4种！
                </p>
                <p className="mt-1 text-sm text-[var(--text-secondary)]">
                  你发现了：只要长 + 宽 = 8，周长就是16
                </p>
                <button
                  onClick={() => {
                    setExercise(2);
                    setHighlight(null);
                  }}
                  className="mt-4 rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                >
                  继续练习2 →
                </button>
              </div>
            )}

            {/* 练习2揭示 */}
            {exercise === 2 && ex2Selected.size >= 2 && (
              <div className="mt-6 animate-float-in text-center">
                <p className="text-lg font-semibold text-[var(--signal-success)]">
                  周长12cm的长方形有3种！
                </p>
                <p className="mt-1 text-sm text-[var(--text-secondary)]">
                  你发现了：只要长 + 宽 = 6，周长就是12
                </p>
              </div>
            )}
          </div>
        </div>
      ) : (
        /* 完成阶段 */
        <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
          <div className="mb-2 text-4xl">🎉</div>
          <p className="text-lg font-semibold text-[var(--text)]">
            {completeMsg}
          </p>
          <p className="mt-2 text-sm text-[var(--text-secondary)]">
            你学会了：给定周长，可以画出好几种不同的长方形！
          </p>
          {nextStep && (
            <Link
              href={nextStep.path}
              className="mt-6 inline-flex items-center gap-2 rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
            >
              下一步：{nextStep.label} →
            </Link>
          )}
        </div>
      )}
    </StepShell>
  );
}
